// Bygger Anthropic-anropet utifrån det appen skickar.
// Appen POSTar: { session_id, subject, grade_goal, messages[], strengths[], weaknesses[] }

const body = $input.first().json.body || {};

const subject   = (body.subject || '').trim() || 'ditt ämne';
const gradeGoal  = ['E', 'C', 'A'].includes(body.grade_goal) ? body.grade_goal : 'C';
const strengths  = Array.isArray(body.strengths) ? body.strengths.filter(Boolean) : [];
const weaknesses = Array.isArray(body.weaknesses) ? body.weaknesses.filter(Boolean) : [];

// Sanera meddelanden. Anthropic kräver att listan börjar med 'user' och
// alternerar. Appen kan skicka en tom lista vid första frågan.
let messages = Array.isArray(body.messages) ? body.messages : [];
messages = messages
  .filter(m => m && typeof m.content === 'string' && m.content.trim())
  .map(m => ({
    role: m.role === 'assistant' ? 'assistant' : 'user',
    content: m.content.trim(),
  }));

while (messages.length && messages[0].role !== 'user') {
  messages.shift();
}

if (!messages.length) {
  throw new Error('Inga meddelanden att skicka.');
}

// Behåll de senaste 20 turerna — håller kostnad och svarstid nere.
if (messages.length > 20) {
  messages = messages.slice(-20);
  while (messages.length && messages[0].role !== 'user') messages.shift();
}

const nivaBeskrivning = {
  E: 'Eleven siktar på betyget E. Håll dig till grunderna. Förklara ett steg i taget, med konkreta vardagsexempel. Undvik fackuttryck om du inte förklarar dem direkt.',
  C: 'Eleven siktar på betyget C. Förklara sambanden, inte bara vad som gäller. Använd ämnets begrepp men förklara dem. Be eleven motivera sina svar.',
  A: 'Eleven siktar på betyget A. Förvänta dig nyans. Utmana med följdfrågor, be om jämförelser och kritisk granskning. Använd ämnets begrepp obehindrat.',
};

const delar = [
  `Du är SkolAI, en studieassistent för svenska gymnasieelever. Eleven pluggar ${subject} hemma, på egen hand.`,
  '',
  nivaBeskrivning[gradeGoal],
  '',
  'Så här arbetar du:',
  '- Svara på svenska, i ett vänligt och rakt tonläge. Prata med eleven, inte till.',
  '- Ge aldrig färdiga svar på uppgifter rakt av. Led fram till svaret med frågor och delsteg.',
  '- Håll svaren korta. Ett stycke eller en kort punktlista räcker nästan alltid.',
  '- Vet du inte, säg det. Hitta aldrig på fakta, årtal eller källor.',
  `- Håll dig till ${subject}. Frågar eleven om något helt annat, säg vänligt att du är här för ${subject}.`,
];

if (strengths.length) {
  delar.push('', `Eleven är redan stark på: ${strengths.join(', ')}. Lägg inte tid på det om eleven inte ber om det.`);
}

if (weaknesses.length) {
  delar.push('', `Eleven har haft svårt med: ${weaknesses.join(', ')}. Var extra tydlig där, och koppla gärna nya saker till detta.`);
}

return [{
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    system: delar.join('\n'),
    messages,
  },
}];

// Plockar ut texten. Appen läser data.reply och inget annat.
const r = $input.first().json;

if (r && Array.isArray(r.content) && r.content[0] && r.content[0].text) {
  return [{ json: { reply: r.content[0].text } }];
}

// Anthropic svarade med fel — logga hela svaret i n8n, ge eleven något begripligt.
console.log('Ovantat svar fran Anthropic:', JSON.stringify(r));

const msg = r && r.error && r.error.message ? r.error.message : 'okänt fel';

return [{
  json: {
    reply: 'Jag kunde inte svara just nu. Försök igen om en liten stund.',
    error: msg,
  },
}];
